import boto3
from botocore.exceptions import ClientError

sns = boto3.client('sns')

def create_subscription(topic_arn, endpoint):
    try:
        response = sns.subscribe(
            TopicArn=topic_arn,
            Protocol='https',
            Endpoint=endpoint
        )
        print(f'Subscription created: {response["SubscriptionArn"]}')
    except ClientError as e:
        if e.response['Error']['Code'] == 'InvalidParameter':
            print(f'Invalid parameter: {e.response["Error"]["Message"]}')
        else:
            print(f'Failed to create subscription: {e}')

def main():
    topic_arn = input("Enter the SNS Topic ARN: ")
    endpoint = input("Enter the URL for the notification webhook: ")

    create_subscription(topic_arn, endpoint)

if __name__ == "__main__":
    main()